package com.pos;
import javax.swing.*; import java.awt.*; import java.sql.*;
public class RegisterDialog extends JDialog {
 private final String[] names={"Username","Password","Full Name","Email","Phone","Address","Customer Code","Birth Date (YYYY-MM-DD)","Loyalty Number"}; private final JTextField[] fields=new JTextField[names.length];
 public RegisterDialog(Frame owner){ super(owner,"Register Customer Account",true);setSize(550,530);setLocationRelativeTo(owner);JPanel p=new JPanel(new GridBagLayout());p.setBorder(BorderFactory.createEmptyBorder(15,15,15,15));GridBagConstraints g=new GridBagConstraints();g.insets=new Insets(4,4,4,4);g.fill=GridBagConstraints.HORIZONTAL;for(int i=0;i<names.length;i++){g.gridx=0;g.gridy=i;p.add(new JLabel(names[i]+":"),g);g.gridx=1;fields[i]=i==1?new JPasswordField(23):new JTextField(23);p.add(fields[i],g);}JButton save=new JButton("Create Account"),cancel=new JButton("Cancel");g.gridx=0;g.gridy=names.length;p.add(save,g);g.gridx=1;p.add(cancel,g);add(p);save.addActionListener(e->save());cancel.addActionListener(e->dispose()); }
 private void save(){ if(fields[0].getText().trim().isEmpty()||fields[1].getText().length()<6||fields[2].getText().trim().isEmpty()||fields[3].getText().trim().isEmpty()){UIUtils.info(this,"Username, password (minimum 6), full name and email are required.");return;} Connection c=null;try{ c=DB.getConnection();c.setAutoCommit(false); PreparedStatement u=c.prepareStatement("INSERT INTO users(username,password_hash,full_name,email,phone,address,role,status) VALUES(?,?,?,?,?,?,'CUSTOMER','ACTIVE')",Statement.RETURN_GENERATED_KEYS);u.setString(1,fields[0].getText().trim());u.setString(2,PasswordUtil.hash(fields[1].getText()));u.setString(3,fields[2].getText().trim());u.setString(4,fields[3].getText().trim());u.setString(5,fields[4].getText().trim());u.setString(6,fields[5].getText().trim());u.executeUpdate();ResultSet k=u.getGeneratedKeys();k.next();int uid=k.getInt(1); PreparedStatement cp=c.prepareStatement("INSERT INTO customer_profiles(user_id,customer_code,birth_date,loyalty_number,loyalty_points,credit_limit) VALUES(?,?,?,?,0,0)"); cp.setInt(1,uid);cp.setString(2,fields[6].getText().trim().isEmpty()?"CUS-"+uid:fields[6].getText().trim());cp.setObject(3,fields[7].getText().trim().isEmpty()?null:fields[7].getText().trim());cp.setString(4,fields[8].getText().trim().isEmpty()?"LOY-"+uid:fields[8].getText().trim());cp.executeUpdate(); c.commit();UIUtils.info(this,"Registration successful. You may now log in.");dispose(); }catch(Exception e){try{if(c!=null)c.rollback();}catch(Exception ignored){} UIUtils.error(this,e);} finally{try{if(c!=null)c.close();}catch(Exception ignored){}} }
}
